args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT
  ?countryLabel
  ?parliamentLabel
  (SUM(?seats) AS ?leftSeats)
  ?totalSeats
  ((SUM(?seats) * 100.0 / ?totalSeats) AS ?percentage)
WHERE {
  ?country wdt:P261 wd:Q142;
          wdt:P267 ?parliament.
  ?parliament wdt:P1022 ?totalSeats.

  ?party wdt:P167 wd:Q4947170.
  ?party p:P2551 ?statement;
         ps:P2551 ?seats;
         pq:P2117 ?parliament.

  OPTIONAL { ?country rdfs:label ?countryLabel FILTER (LANG(?countryLabel) = 'en') }
  OPTIONAL { ?parliament rdfs:label ?parliamentLabel FILTER (LANG(?parliamentLabel) = 'en') }
}
GROUP BY ?country ?parliament ?totalSeats
